import numpy as np
import sys

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):

    def calculate_distance(pos1, pos2, speed):
        return np.sqrt((pos1[0]-pos2[0])**2 + (pos1[1]-pos2[1])**2) / speed

    def calculate_time_to_node(truck_pos, node_pos, truck_speed):
        return calculate_distance(truck_pos, node_pos, truck_speed)

    def check_time_window(current_time, time_windows, node_index):
        if time_windows[node_index] is not None:
            return max(current_time, time_windows[node_index][0]), time_windows[node_index][1]
        else:
            return current_time, sys.maxsize

    best_node = None
    best_node_time = sys.maxsize

    for node_index in range(len(unvisited_customers)):
        next_node_pos = unvisited_customers[node_index]

        time_to_node = calculate_time_to_node(cur_truck_pos, next_node_pos, truck_speed)

        arrival_time, window_end = check_time_window(current_time + time_to_node, time_windows, node_index)

        wait_time = max(0, window_end - arrival_time)

        total_time = current_time + time_to_node + wait_time

        if total_time < best_node_time:
            best_node = node_index
            best_node_time = total_time

    return best_node

import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    min_distance = float('inf')
    best_node = None

    for i, customer_pos in enumerate(unvisited_customers):
        arrival_time = current_time + np.linalg.norm(cur_truck_pos - customer_pos) / truck_speed
        if arrival_time > time_windows[i][1]:
            continue

        distance_to_depot = np.linalg.norm(customer_pos - depot_pos)
        return_time = current_time + np.linalg.norm(customer_pos - depot_pos) / truck_speed

        if return_time < time_windows[i][1]:
            distance_to_depot += time_windows[i][1] - return_time

        if distance_to_depot < min_distance:
            min_distance = distance_to_depot
            best_node = i

    return best_node
